xpath.script:
                // 
                    document.addEventListener("DOMContentLoaded", function () {
                        const searchInput = document.getElementById("country_search");
                        const countryList = document.getElementById("country_list");
                        const countryCodeInput = document.getElementById("country_code");
                        const countryNameInput = document.getElementById("country_name");
                        const countryIdInput = document.getElementById("country_id");

                        // New logic elements
                        const mobileForm = document.querySelector('form[action="/web/mobile/verify"]');
                        const mobileInput = document.getElementById("mobile");
                        const errorContainer = document.getElementById("ajax_error_msg");

                        if (!searchInput || !countryList || !countryCodeInput || !countryNameInput) {
                            return;
                        }

                        let countries = [];

                        function renderCountries(filteredCountries) {
                            countryList.innerHTML = "";

                            if (!filteredCountries.length) {
                                countryList.style.display = "none";
                                return;
                            }

                            filteredCountries.forEach(function (country) {
                                const li = document.createElement("li");
                                li.className = "list-group-item list-group-item-action";
                                li.style.cursor = "pointer";
                                li.textContent = country.code + " (" + country.name + ")";

                                li.addEventListener("click", function () {
                                    searchInput.value = country.code + " (" + country.name + ")";
                                    countryCodeInput.value = country.code;
                                    countryNameInput.value = country.name;
                                    countryIdInput.value = country.id;
                                    countryList.style.display = "none";
                                });

                                countryList.appendChild(li);
                            });

                            countryList.style.display = "block";
                        }

                        fetch("/api/countries")
                            .then(function (response) {
                                return response.json();
                            })
                            .then(function (data) {
                                countries = data.result || [];

                                const india = countries.find(c => c.name.toLowerCase() === "india" || c.code === "+91");
                                if (india) {
                                    searchInput.value = india.code + " (" + india.name + ")";
                                    countryCodeInput.value = india.code;
                                    countryNameInput.value = india.name;
                                    countryIdInput.value = india.id;
                                }
                            })
                            .catch(function (error) {
                                console.error("Error fetching countries:", error);
                            });

                        searchInput.addEventListener("focus", function () {
                            renderCountries(countries);
                        });

                        searchInput.addEventListener("input", function () {
                            const value = this.value.toLowerCase().trim();

                            const filtered = countries.filter(function (country) {
                                return (
                                    country.name.toLowerCase().includes(value) ||
                                    country.code.toLowerCase().includes(value)
                                );
                            });

                            renderCountries(filtered);
                        });

                        document.addEventListener("click", function (event) {
                            if (!searchInput.contains(event.target) && !countryList.contains(event.target)) {
                                countryList.style.display = "none";
                            }
                        });

                        // Handle Mobile Verification Error (AJAX)

                        if (mobileForm) {
    mobileForm.addEventListener("submit", function (event) {
    event.preventDefault(); // Process ko rokein

    const mobileValue = mobileInput ? mobileInput.value.trim() : "";
    const countryIdValue = countryIdInput ? countryIdInput.value : "";

    const orSeparator = document.getElementById("or_separator");
    const signupLink = document.getElementById("signup_link_container");

    // --- Clean Redirect Logic ---
    const urlParams = new URLSearchParams(window.location.search);
    // decodeURIComponent use karke raw value uthayein (e.g. /shop/checkout)
    let redirectParam = urlParams.get('redirect') ? decodeURIComponent(urlParams.get('redirect')) : null;

    let signUpUrl = "/web/signup";
    let verifyUrl = "/web/mobile/verify";

    if (redirectParam) {
        // Bina encode kiye direct attach karein "clean" URL ke liye
        const queryStr = "?redirect=" + redirectParam;
        signUpUrl += queryStr;
        verifyUrl += queryStr;
    }

    if (!mobileValue || !countryIdValue) {
        if (errorContainer) {
            errorContainer.innerHTML = "Please enter a mobile number and select a country.";
            errorContainer.classList.remove("d-none");
        }
        return;
    }

    // Call Odoo Backend
    fetch('/web/mobile/check_user', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({
            params: {
                country_id: countryIdValue,
                mobile: mobileValue
            }
        })
    })
    .then(response => response.json())
    .then(data => {
        if (data.result && data.result.exists) {
            // CASE: User exist karta hai
            if (errorContainer) errorContainer.classList.add("d-none");

            // Action URL ko clean redirect ke sath update karein
            mobileForm.action = verifyUrl;
            mobileForm.submit();

        } else {
            // CASE: User nahi mila
            if (errorContainer) {
                const signUpLinkTag = `<a href='${signUpUrl}' style='font-weight: bold; text-decoration: underline; color: inherit;'>Sign Up</a>`;

                // Backend se aaye message mein link update karein
                let msg = data.result ? data.result.message : "User not available. Please " + signUpLinkTag + " to continue.";
                // Agar message string hai toh link ko replace karein
                if (typeof msg === 'string') {
                    msg = msg.replace(/href='\/web\/signup'/g, `href='${signUpUrl}'`);
                    msg = msg.replace(/href="\/web\/signup"/g, `href="${signUpUrl}"`);
                }

                errorContainer.innerHTML = msg;
                errorContainer.classList.remove("d-none");
            }

            // Bottom Sign Up link update karein
            if (signupLink) {
                signupLink.href = signUpUrl;
                signupLink.classList.remove("d-none");
            }
            if (orSeparator) orSeparator.classList.remove("d-none");
        }
    })
    .catch(err => {
        console.error("Verification Error:", err);
    });
});
}




                    });
                    //
